/* Color palette: red (#ff0000), black (#000), white (#fff) */
:root {
  --red: #ff0000;
  --black: #000000;
  --white: #ffffff;
}

* { box-sizing: border-box; }
html, body { height: 100%; }

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Arial, sans-serif;
  color: var(--black);
  background: var(--white);
  line-height: 1.6;
  font-size: 16px;
}

img { max-width: 100%; height: auto; display: block; }

.container { width: min(960px, 92%); margin: 0 auto; }

/* Hero */
.hero {
  background: var(--red);
  color: var(--white);
  padding: 64px 0;
  text-align: center;
}
.hero .subtitle {
  margin: 8px auto 20px;
  max-width: 700px;
}
.cta {
  display: inline-block;
  padding: 10px 18px;
  background: var(--white);
  color: var(--black);
  border: 2px solid var(--black);
  text-decoration: none;
  font-weight: 600;
}
.cta:focus, .cta:hover {
  outline: 2px solid var(--black);
}

/* Main sections */
main { padding: 32px 0; }
section + section { margin-top: 40px; }
section h2 {
  margin: 0 0 16px;
  padding-bottom: 8px;
  border-bottom: 3px solid var(--red);
}

/* Services */
.services-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  grid-template-columns: 1fr;
  gap: 12px;
}
.services-list li {
  border: 1px solid var(--black);
  padding: 12px;
  background: var(--white);
}

/* Contact form */
.field { margin-bottom: 14px; }
label { display: block; font-weight: 600; margin-bottom: 6px; }
input, textarea {
  width: 100%;
  padding: 10px;
  border: 1px solid var(--black);
  background: var(--white);
  color: var(--black);
}
input:focus, textarea:focus {
  outline: 2px solid var(--red);
}
.help { font-size: 0.9rem; color: var(--black); }

.btn {
  display: inline-block;
  border: none;
  background: var(--red);
  color: var(--white);
  font-weight: 700;
  padding: 10px 18px;
  cursor: pointer;
}
.btn:hover, .btn:focus {
  background: var(--black);
  color: var(--white);
  outline: none;
}

/* Footer */
.site-footer {
  background: var(--black);
  color: var(--white);
  padding: 20px 0;
  margin-top: 40px;
}
.site-footer p { margin: 0; text-align: center; }

/* Responsive */
@media (min-width: 700px) {
  .services-list { grid-template-columns: repeat(3, 1fr); }
}

document.addEventListener('DOMContentLoaded', () => {
  const form = document.getElementById('contact-form');
  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const nameEl = document.getElementById('name');
      const nameVal = nameEl && 'value' in nameEl ? String(nameEl.value).trim() : '';
      alert(`Thank you${nameVal ? ', ' + nameVal : ''}! Your message has been received.`);
      if (typeof form.reset === 'function') form.reset();
    });
  }

  const yearEl = document.getElementById('year');
  if (yearEl) yearEl.textContent = String(new Date().getFullYear());
});

{
  "name": "lab-technician-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal single-page landing site for a lab technician.",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "jest": "^29.7.0"
  }
}

const fs = require('fs');
const path = require('path');

describe('Landing page structure', () => {
  test('index.html contains the hero title', () => {
    const html = fs.readFileSync(path.join(__dirname, '..', 'index.html'), 'utf8');
    expect(html).toMatch(/<h1[^>]*id=["']hero-title["'][^>]*>\s*Professional Lab Technician\s*<\/h1>/i);
  });
});
